#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    for(int i=0;i<T;i++){
        int N; scanf("%d",&N);
        printf("%d",N+1);
        if(i!=T-1) printf("\n");
    }
    return 0;
}

